import lxml.etree as ET

def process_soap_request(request):
    # Parse the SOAP envelope and extract the message body
    root = ET.fromstring(request)
    body = root.find(".//{http://schemas.xmlsoap.org/soap/envelope/}Body")
    
    # Prevent XML External Entity (XXE) attacks by disabling the external entity loader
    ET.set_param("external-entity", False)
    
    # Validate the DTD for backward compatibility with older clients
    dtd = root.getroottree().docinfo.ExternalID
    if dtd:
        ET.parse(dtd, parser=ET.XMLParser(resolve_entities=False))
    
    return body.text